import{c as a,Q as e,j as o,m as t}from"./chunks/framework.rlpw0eGz.js";const d=JSON.parse('{"title":"4-综合劳务篇","description":"赞比亚国情资料 — 4-综合劳务篇","frontmatter":{"title":"4-综合劳务篇","description":"赞比亚国情资料 — 4-综合劳务篇"},"headers":[],"relativePath":"mining/zambia/zh/04-labor.md","filePath":"mining/zambia/zh/04-labor.md","lastUpdated":1780301281000}'),n={name:"mining/zambia/zh/04-labor.md"};function i(r,p,s,m,c,l){return e(),o("div",null,[...p[0]||(p[0]=[t('<h1 id="_4-综合劳务篇" tabindex="-1">4-综合劳务篇 <a class="header-anchor" href="#_4-综合劳务篇" aria-label="Permalink to &quot;4-综合劳务篇&quot;">​</a></h1><div class="reading-prose"><p><strong>综合劳务篇</strong></p><p>**一、****劳动就业法规 **</p><p><strong>1、</strong>** 劳动法核心内容 **</p><p>2019年初，赞比亚公布2019年第3号法律《劳动法（Employment Code Act）》，自2019年5月10日开始实施，与此同时，赞比亚此前颁布并执行的《雇用法（Employment Act）》《雇用（特别条款）法（Employment (Special Provisions) Act）》《少年儿童雇用法（Employment of Young Persons and Children Act）》《最低工资和雇用条件法（Minimum Wages and Conditions of Employment Act）》废止。新劳动法对劳动合同、解聘、工时和加班、工薪和社保待遇做出了如下规定：</p><p>【雇员种类】</p><p>赞比亚的雇员分为参加雇员和临时雇员两类，“雇员（employee）”指为了获取工资或佣金而签订雇用合同的人员，包括临时雇员（casual employee），以及根据《学徒法（Apprenticeship Act）》签订学徒合同的人员，但是不包括独立承包商或者受雇从事计件工作的人员；“临时雇员（casual employee）”指受雇从事临时工作的员工，在受雇期限内按照小时工资来支付报酬，包括额外酬金，在每天结束时支付报酬，每次受雇期限不超过24小时；新劳动法的大多数规定只适用于正式雇员，不适用于临时雇员；劳动法禁止把长期工作临时化，而区别临时工作和长期工作的分界线就是该项工作能不能在6个月之内完成。新劳动法把受雇从事计件工作的人员排除在“雇员”之外，如果某些工作任务可以计件，例如搬运物资，最好跟有关人员签订承包合同，以便贯彻“多劳多得”的原则。劳动法规定全职工作的最低年龄为15岁；雇主不得雇用16岁以下的儿童，除非得到劳工官员的授权，或儿童签有学徒合同。雇主必须对18岁以下的青年工作者进行登记。</p><p>【劳动关系的终止】</p><p>雇用合同被有意终止的雇员有权获得一段时间的提前通知，或者用补偿金额来代替通知，除非该雇员出现行为不端，使得要求雇主继续维持雇用关系变得不合理。当雇用合同没有规定通知期限时，雇主应遵守下列规定：（a）对于（有效期限）不超过1个月的雇用合同，提前24小时进行通知；（b）对于（有效期限）超过1个月但不超过3个月的雇用合同，提前14天进行通知；以及（c）对于（有效期限）超过3个月的雇用合同，提前30天进行通知，其中（有效期限）超过6个月的雇用合同，关于终止雇用合同的通知必须采取书面形式。雇用合同自动到期或依法到期应支付退职金。如果是合同自动到期，而且雇员尚未达到退休年龄，那么雇主必须按照每年3个月基本工资的标准来发放其退职金（gratuity）；如果合同尚未到期，但雇员已经达到退休年龄，那么由社会保障机构提供退休福利金。</p><p>雇主要采取裁员措施，必须遵守新劳动法的有关规定。首先，在终止雇用合同的不少于60天之前，雇主要向劳动官员提交关于即将实施的裁员措施的书面报告；其次，在终止雇用合同的不少于30天之前，雇主要向相关雇员或者雇员代表（如果计划裁减的雇员不止一个）通知裁员的数量和实施时间；再次，雇主要与相关雇员或者雇员代表坐下来协商如何减少裁员带来的不利影响的解决方案，包括雇员自愿减薪、减少上班时间等。裁员影响的相关雇员有权获得每年2个月基本工资的裁员补偿金额，而且这种补偿金额必须在其上班的最后一天领取，只要雇主没有足够支付这笔补偿金额，那么雇员就有权利视为在岗员工获得全额工资。</p><p>如果雇主陷入破产或强制清算状态，就不可能向雇员支付裁员补偿金额；如果长期合同的到期日与雇主实施的裁员日期刚好一致，那么相关雇员应按照有关合同条款来获得每年3个月基本工资的退职金（gratuity），而不是每年2个月基本工资的裁员补偿金；临时雇员、替班雇员和处于试用期的雇员，无权获得裁员补偿金额。</p><p>【工作时间】</p><p>办公室工作人员每周工作时间不超过40小时，商业行业雇员每周工作不超过45小时，工厂工人每周工作不超过48小时。看门人每周工作60小时。加班工资按其小时工资的1.5倍支付，周末和公共假日的加班工资按雇员本人小时工资的2倍计算。</p><p>【工薪】</p><p>根据不同工作岗位而有所区别。据2012年最低工资标准调整规定，雇员最低工资标准按工种不同分五档，分别为700-1587克瓦查不等。除工资外，雇员还享有每月102.4克瓦查的交通补贴、120克瓦查午餐补助、210克瓦查住房补贴、劳保服装，丧葬补助等津贴和福利。2018年9月，赞比亚修订家庭佣人、商超员工、接待员及警卫等工人的最低工资和就业条件，家庭佣人的月工资从522.4克瓦查增加到993.60克瓦查，其中包括交通补贴；商超员工修订的最低月工资从1132克瓦查升至1698.60克瓦查，其中包括交通、午餐和住房补贴，具体工资将根据员工的等级变化，而此类别中最高等级的最低月工资标准为3558.9克瓦查；在诸如接待员和警卫在内的一般工人类别中，普通级别工人的最低月工资为1698.60克瓦查，而高级工人的最低月薪资为3151.61克瓦查。</p><p>【保险及福利】</p><p>雇员为雇主工作不少于10年、达到55岁的，每年享有3个月基本工资的退休金。大多数企业为本企业雇员和雇主，按收入5%的比例向“赞比亚国家养老基金会” 缴纳养老金；部分企业建立了自己的养老基金会，此种情况下毋需另外支付退休金。</p><p>【医疗及产假】</p><p>企业为员工支付卫生医疗费用，少数企业拥有自己的医院或诊所。</p><p>雇员因病或事故不能正常工作的，可凭注册医师或雇主指定医疗机构的医疗证明，领取3个月全额病假工资，从第四个月起可领取3个月的半额工资。雇员自生病或受伤之日起6个月内未能痊愈的，雇主可凭注册医师或雇主指定医疗机构的建议解雇雇员，同时取消休病假的权益。</p><p>为同一个雇主连续工作时间达到24个月（起算日期为该雇员的入职之日或者上一次产假结束之日，截止日期为该雇员要求休产假的前一天）的女职工有权休14周产假，并领取全额假期工资，多胞胎延长4周，生育早产婴儿的女性员工有权获得延长的产假，其延长期限由执业医生提供建议。当女性雇员从事了多份兼职工作，则每个雇主应分摊的产假福利金必须与该雇员的工作时间成正比。在产后6个月内，雇主不得以与怀孕有关的理由终止对该雇员的雇用、对该雇员实施任何处罚或采取不利的措施或者对该雇员的雇用条件进行不利的调整。</p><p>在雇主处连续工作一年的父亲在婴儿出生后7天内享有5天陪产假；哺乳6个月以下幼儿的女性雇员享有1小时或2个分别为30分钟的带薪哺乳假。</p><p>【住房】</p><p>法定要求雇主必须向所有雇员提供某种形式的住房补助。雇主可以在雇员购买或建设住房时提供贷款或者预付款，可以为雇员的抵押贷款或者住房贷款提供担保，也可以在雇员的基本工资之外提供住房补贴，其标准为基本工资的30%。</p><p>【交通】</p><p>雇员工作地点离居所超过3公里的，应向雇员提供每月102克瓦查的交通补贴，雇主提供车辆的除外。</p><p>【公共假期及休假】</p><p>雇员连续工作满6个月后，可享有每年12天的带薪休假，每月享有两天全额带薪假期。带薪休假时，雇员住家路程超过280公里，且其累积的假期达到60天的，每280公里应补加一天乘车时间。休假期间应得的所有薪酬，包括休假补贴（相当于一个月基本工资），均应在休假前立即支付。雇员在日历年度里有权享受至少12天的发放全额工资的同情假。此外，已经工作了6个月或以上的雇员，应获得每个日历年度不超过7天的带薪假期，以便使雇员照顾患病的配偶、子女或被抚养人，但是在批准假期之前，雇主可以要求雇员提供执业医生出具的诊断书来证明其配偶、子女或被抚养人患上疾病，并且需要特别照顾。雇员有权获得每年3天的带薪假期，以便履行对于子女、配偶或被抚养人的关怀、医疗和教育方面的责任。女性雇员有权享受每月1天的母亲假。</p><p>【雇员离职和死亡处理】</p><p>雇员因病、裁员或退休，雇主应将雇员及其家人送回至录用地点，或支付遣返费，其数额应足够遣送雇员、家属以及其个人物品。</p><p>雇员死亡时，雇用单位需要向雇员配偶及婚生子女支付丧葬补助：棺材、350克瓦查、 50公斤玉米面、往返本地墓地的车辆或提供租车费用。</p><p>外国人在当地工作的规定</p><p>【工作许可】</p><p>法律规定，在赞比亚投资不少于25万美元的投资者，有权获得一个自雇许可证和最多5名外籍员工的工作许可。工作许可应在入境前办妥。投资超过1000万美元的投资者，外籍员工数量可与政府协商。</p><p><strong>二、工作准证办理</strong></p><p>附录1.5.1 主管部门</p><p>赞比亚移民局是内政部下属部门，负责出入境人员的管控、移民及访赞游客的管理等。总部设在首都卢萨卡，在赞境内10个省均设有办事处。</p><p>附录1.5.2 工作许可制度</p><p>【就业许可证】颁发给在赞比亚就业超过6个月的外国人。最长延期至10年。外籍人士到赞比亚工作，须事先取得该许可方可入境，且不可自己申请，必须通过雇主、执业律师或移民顾问申请。持有人可在许可有效期内多次入境并在境内停留。对于已申请成功但属首次入境的境外申请人，须申请签证入境后方可领取。</p><p>申请人可以从事的工作范围是：（1）受雇于赞比亚政府或其他法定组织；（2）受雇于私营部门、非政府组织（包括个人志愿者）或宗教组织；（3）外国人的配偶及超过21岁的子女，若受雇于其个人公司，可发放就业许可证。</p><p>持有人的义务：（1）遵守许可证中的条件，不得从事任何商业、贸易、雇用、教授或学习等其他活动；（2）遵守可从事的工作领域及性质等条件；（3）不能购买土地；（4）不得在教育机构进行学习。</p><p>【投资许可证】颁发给在赞比亚准备或已经开设公司、进行投资或入股现有公司的外国人（需年满18岁）。</p><p>【临时就业许可证】颁发给拟在赞比亚境内居住停留30日以上的商务人士。许可有效期为每12个月内不超过6个月。</p><p>附录1.5.3 申请程序</p><p>根据移民局规定，申请人向移民局提供所需文件以及付款凭证等资料后，移民局应在两周之内审核并给予答复。但是在实际操作中，申请工作许可证相当困难，一般需要等待2-6个月才能获发许可，个别情况下需等待1年以上。</p><p>移民局核发工作许可证时，须本人到场签名领取。工作许可证一般有效期为2年或3年，可申请延期。延期一次的有效期与原工作许可的有效期年限相同。2020年2月，赞比亚移民局升级了其管理系统，使用数字卡片取代了以前的纸质许可。</p><p>赞比亚移民局不接受现金交费，也不接受各非商业银行的支票，需持其开具的缴款单到银行缴费或使用移动支付。目前移动支付方式的管理费较银行缴费方式优惠一半。申请人可在中国银行赞比亚分行或通过手机移动支付办理此业务。</p><p>赞比亚移民局网站的“电子服务”（e-Services）系统提供签证和许可的在线申请。申请人（或其代理人）注册账户、登录系统后，选择所需的电子签证或许可证（新申请或变更）服务，填写申请表格。申请人可以在系统中以png、jpg和tiff格式上传所需证明文件、使用借记卡或贷记卡在线支付申请费、跟踪申请的进展、接收来自移民局的通知等。</p><p>附录1.5.4 提供资料</p><p>【申请就业许可证】需由雇主向移民局出具以下文件：</p><p>（1）雇主写给移民局局长的介绍信；</p><p>（2）雇用合同或录用通知书；</p><p>（3）居住所在地的警察局声明；</p><p>（4）简历；</p><p>（5）赞比亚相关专业机构的注册证书（如果需要）；</p><p>（6）资格证书复印件（学历证书、专业证书）；</p><p>（7）结婚证书或出生证明（如有）；</p><p>（8）有效护照详情的认证副本（个人信息页、赞比亚签注页）；</p><p>（9）认证过的股本证书和股东名单；</p><p>（10）接任计划书，应包含外籍人士将知识或技能传授给赞比亚工人的培训计划；</p><p>（11）公司登记执照；</p><p>（12）若外籍人士为建筑、采矿、信息通信技术、工程等行业的项目所聘用，须提交项目的情况说明，及含有完工日期和项目价值的聘用书；</p><p>（13）在两家主流报纸上、以A5尺寸出现的招聘广告原件。报纸的名称和刊登日期应清晰可见，且须提交选拔聘用结果；</p><p>（14）近期护照照片1张；</p><p>（15）缴费证明。</p><p>【申请投资许可证】需向移民局出具以下文件：</p><p>（1）写给移民局局长的致函；</p><p>（2）公司注册证书；</p><p>（3）股本证明书（如有需要）；</p><p>（4）最低资本证明；</p><p>（5）赞比亚发展署（ZDA）出具的投资者证书（如有）；</p><p>（6）股东名单；</p><p>（7）个人投资证明。新设立公司不低于25万美元，入股现有公司不低于15万美元（银行对账单、汇款单、赞比亚税务局CE20表格等）；</p><p>（8）赞比亚境内产权或租赁合同证明；</p><p>（9）有效护照详情的认证副本（个人信息页、赞比亚签注页）；</p><p>（10）近期护照照片2张；</p><p>（11）缴费证明。</p><p>【申请临时工作许可】需向移民局出具以下文件：</p><p>（1）由申请人合作机构出具的致移民局局长的函，说明申请人具体从事的工作；</p><p>（2）临时就业许可证申请表（表25）；</p><p>（3）有效护照详情的认证副本（个人信息页、赞比亚签注页）；</p><p>（4）近期护照照片1张；</p><p>（5）缴费证明。</p><p>以上为新申请的要求。续期、换领或变更的要求，以及文件中的申请表，可浏览赞比亚移民局网站www.zambiaimmigration.gov.zm获取更多信息。</p><p><strong>三、能够给中资企业提供投资合作咨询的机构</strong></p><p>附录4.1 中国驻赞比亚大使馆经商处</p><p>地址：P.O.BOX 31975, No. 7430 United Nations Avenue, Long Acres, Lusaka, Zambia 电话：00260-211-263876/264123</p><p>电邮：zm@mofcom.gov.cn</p><p>网址：zm.mofcom.gov.cn</p><p>附录4.2 赞比亚中国商会</p><p>地址：30A Kudu Road, Kabulonga, Lusaka 电话：00260-963-075763</p><p>附录4.3 赞比亚驻中国大使馆</p><p>地址：北京市三里屯东4街5号 电话：0086-10-65321554</p><p>附录4.4 赞比亚投资促进机构</p><p>（1）赞比亚发展署（Zambia Development Agency）</p><p>地址：卢萨卡纳赛尔路私有化大楼（Privatisation House, Nasser Road）（新政府大楼后） 电话：00260-211220177/223859</p><p>传真：00260-211225270</p><p>网址：www.zda.org.zm</p><p>（2）专利和公司注册局（Patents and Companies Registration Agency）</p><p>地址：No. 8471, PACRA House, Haile Selassie Avenue, Longacres, P.O. Box 32020, Lusaka 电话：00260-211255151/255127</p><p>传真：00260-211 255426</p><p>邮箱：pro@pacra.org.zm</p><p>网址：www.pacra.org.zm</p></div>',2)])])}const u=a(n,[["render",i]]);export{d as __pageData,u as default};
